import os

def create_files():
    files = {
        "frontend/tailwind.config.js": "/** @type {import('tailwindcss').Config} */\nexport default {\n  content: [\n    \"./index.html\",\n    \"./src/**/*.{js,ts,jsx,tsx}\",\n  ],\n  darkMode: 'class',\n  theme: {\n    extend: {\n      colors: {\n        background: \"#0a0a0a\",\n        surface: \"#171717\",\n        border: \"#262626\",\n        primary: \"#3b82f6\",\n        \"primary-dark\": \"#2563eb\",\n        accent: \"#8b5cf6\",\n        success: \"#10b981\",\n        warning: \"#f59e0b\",\n        danger: \"#ef4444\",\n      },\n      animation: {\n        'gradient-x': 'gradient-x 15s ease infinite',\n        'pulse-slow': 'pulse 3s cubic-bezier(0.4, 0, 0.6, 1) infinite',\n      },\n      keyframes: {\n        'gradient-x': {\n          '0%, 100%': {\n            'background-size': '200% 200%',\n            'background-position': 'left center'\n          },\n          '50%': {\n            'background-size': '200% 200%',\n            'background-position': 'right center'\n          },\n        }\n      }\n    },\n  },\n  plugins: [],\n}\n",
        "frontend/src/index.css": "@tailwind base;\n@tailwind components;\n@tailwind utilities;\n\n@layer base {\n  body {\n    @apply bg-background text-gray-100 antialiased selection:bg-primary selection:text-white;\n  }\n}\n\n@layer components {\n  .glass-panel {\n    @apply bg-surface/60 backdrop-blur-xl border border-white/10 shadow-2xl rounded-2xl;\n  }\n  .glass-card {\n    @apply bg-white/5 backdrop-blur-md border border-white/10 rounded-xl hover:bg-white/10 transition-all duration-300;\n  }\n  .btn-primary {\n    @apply bg-gradient-to-r from-primary to-accent hover:from-primary-dark hover:to-primary text-white font-medium rounded-lg px-6 py-2.5 transition-all duration-300 shadow-lg shadow-primary/25;\n  }\n  .btn-secondary {\n    @apply bg-white/10 hover:bg-white/20 border border-white/10 text-white font-medium rounded-lg px-6 py-2.5 transition-all duration-300;\n  }\n}\n",
        "frontend/src/App.tsx": "import React from 'react';\nimport { BrowserRouter as Router, Routes, Route } from 'react-router-dom';\nimport LandingLayout from './layouts/LandingLayout';\nimport AppLayout from './layouts/AppLayout';\nimport Landing from './pages/Landing';\nimport Dashboard from './pages/Dashboard';\nimport WebsiteScanner from './pages/WebsiteScanner';\nimport QRScanner from './pages/QRScanner';\nimport Results from './pages/Results';\nimport History from './pages/History';\nimport Settings from './pages/Settings';\nimport Profile from './pages/Profile';\nimport NotFound from './pages/NotFound';\n\nfunction App() {\n  return (\n    <Router>\n      <Routes>\n        {/* Marketing / Public Routes */}\n        <Route path=\"/\" element={<LandingLayout />}>\n          <Route index element={<Landing />} />\n        </Route>\n        \n        {/* App Routes */}\n        <Route path=\"/app\" element={<AppLayout />}>\n          <Route index element={<Dashboard />} />\n          <Route path=\"scan-website\" element={<WebsiteScanner />} />\n          <Route path=\"scan-qr\" element={<QRScanner />} />\n          <Route path=\"results/:id\" element={<Results />} />\n          <Route path=\"history\" element={<History />} />\n          <Route path=\"settings\" element={<Settings />} />\n          <Route path=\"profile\" element={<Profile />} />\n        </Route>\n\n        {/* Fallback */}\n        <Route path=\"*\" element={<NotFound />} />\n      </Routes>\n    </Router>\n  );\n}\n\nexport default App;\n",
        "frontend/src/layouts/LandingLayout.tsx": "import React from 'react';\nimport { Outlet } from 'react-router-dom';\nimport Navbar from '../components/layout/Navbar';\nimport Footer from '../components/layout/Footer';\n\nconst LandingLayout = () => {\n  return (\n    <div className=\"min-h-screen flex flex-col relative overflow-hidden\">\n      <div className=\"absolute inset-0 bg-gradient-to-br from-background via-surface to-background animate-gradient-x -z-10\"></div>\n      <Navbar />\n      <main className=\"flex-1 flex flex-col pt-20\">\n        <Outlet />\n      </main>\n      <Footer />\n    </div>\n  );\n};\n\nexport default LandingLayout;\n",
        "frontend/src/layouts/AppLayout.tsx": "import React, { useState } from 'react';\nimport { Outlet, Link, useLocation } from 'react-router-dom';\nimport { motion, AnimatePresence } from 'framer-motion';\nimport { LayoutDashboard, Globe, QrCode, History as HistoryIcon, Settings as SettingsIcon, User, Menu, X, ShieldCheck } from 'lucide-react';\n\nconst AppLayout = () => {\n  const [sidebarOpen, setSidebarOpen] = useState(false);\n  const location = useLocation();\n\n  const links = [\n    { path: '/app', name: 'Overview', icon: LayoutDashboard },\n    { path: '/app/scan-website', name: 'Website Scanner', icon: Globe },\n    { path: '/app/scan-qr', name: 'QR Scanner', icon: QrCode },\n    { path: '/app/history', name: 'Scan History', icon: HistoryIcon },\n    { path: '/app/settings', name: 'Settings', icon: SettingsIcon },\n  ];\n\n  return (\n    <div className=\"min-h-screen bg-background flex overflow-hidden\">\n      {/* Mobile Sidebar Overlay */}\n      <AnimatePresence>\n        {sidebarOpen && (\n          <motion.div\n            initial={{ opacity: 0 }}\n            animate={{ opacity: 1 }}\n            exit={{ opacity: 0 }}\n            className=\"fixed inset-0 bg-black/60 backdrop-blur-sm z-40 md:hidden\"\n            onClick={() => setSidebarOpen(false)}\n          />\n        )}\n      </AnimatePresence>\n\n      {/* Sidebar */}\n      <aside className={`fixed inset-y-0 left-0 w-64 glass-panel border-y-0 border-l-0 rounded-none z-50 transform transition-transform duration-300 ease-in-out md:translate-x-0 md:static ${sidebarOpen ? 'translate-x-0' : '-translate-x-full'}`}>\n        <div className=\"flex items-center justify-between h-16 px-6 border-b border-white/10\">\n          <Link to=\"/app\" className=\"flex items-center gap-2 text-xl font-bold bg-clip-text text-transparent bg-gradient-to-r from-primary to-accent\">\n            <ShieldCheck className=\"w-6 h-6 text-primary\" />\n            TrustGuardAI\n          </Link>\n          <button className=\"md:hidden text-gray-400 hover:text-white\" onClick={() => setSidebarOpen(false)}>\n            <X size={24} />\n          </button>\n        </div>\n        <nav className=\"p-4 space-y-1\">\n          {links.map((link) => {\n            const isActive = location.pathname === link.path;\n            const Icon = link.icon;\n            return (\n              <Link\n                key={link.path}\n                to={link.path}\n                onClick={() => setSidebarOpen(false)}\n                className={`flex items-center gap-3 px-4 py-3 rounded-xl transition-all duration-200 ${isActive ? 'bg-primary/20 text-primary border border-primary/30 shadow-[0_0_15px_rgba(59,130,246,0.15)]' : 'text-gray-400 hover:text-white hover:bg-white/5'}`}\n              >\n                <Icon size={20} className={isActive ? 'text-primary' : ''} />\n                <span className=\"font-medium\">{link.name}</span>\n              </Link>\n            );\n          })}\n        </nav>\n      </aside>\n\n      {/* Main Content */}\n      <main className=\"flex-1 flex flex-col h-screen overflow-hidden\">\n        <header className=\"h-16 flex items-center justify-between px-6 glass-panel border-x-0 border-t-0 rounded-none z-30\">\n          <button className=\"md:hidden text-gray-400 hover:text-white\" onClick={() => setSidebarOpen(true)}>\n            <Menu size={24} />\n          </button>\n          <div className=\"flex-1\"></div>\n          <Link to=\"/app/profile\" className=\"flex items-center gap-3 hover:bg-white/5 p-2 rounded-lg transition-colors border border-transparent hover:border-white/10\">\n            <div className=\"w-8 h-8 rounded-full bg-gradient-to-tr from-primary to-accent flex items-center justify-center\">\n              <User size={16} className=\"text-white\" />\n            </div>\n            <span className=\"text-sm font-medium hidden sm:block\">Admin User</span>\n          </Link>\n        </header>\n        <div className=\"flex-1 overflow-auto p-6 md:p-8\">\n          <motion.div\n            key={location.pathname}\n            initial={{ opacity: 0, y: 15 }}\n            animate={{ opacity: 1, y: 0 }}\n            exit={{ opacity: 0, y: -15 }}\n            transition={{ duration: 0.3 }}\n            className=\"max-w-6xl mx-auto\"\n          >\n            <Outlet />\n          </motion.div>\n        </div>\n      </main>\n    </div>\n  );\n};\n\nexport default AppLayout;\n",
        "frontend/src/components/layout/Navbar.tsx": "import React from 'react';\nimport { Link } from 'react-router-dom';\nimport { ShieldCheck } from 'lucide-react';\n\nconst Navbar = () => {\n  return (\n    <nav className=\"fixed top-0 w-full z-50 glass-panel border-x-0 border-t-0 rounded-none h-20 flex items-center px-8 justify-between\">\n      <Link to=\"/\" className=\"flex items-center gap-2 text-2xl font-bold bg-clip-text text-transparent bg-gradient-to-r from-primary to-accent\">\n        <ShieldCheck className=\"w-8 h-8 text-primary\" />\n        TrustGuardAI\n      </Link>\n      <div className=\"hidden md:flex items-center gap-8 text-sm font-medium text-gray-300\">\n        <a href=\"#features\" className=\"hover:text-white transition-colors\">Features</a>\n        <a href=\"#how-it-works\" className=\"hover:text-white transition-colors\">How It Works</a>\n      </div>\n      <div className=\"flex gap-4\">\n        <Link to=\"/app\" className=\"btn-secondary hidden sm:block\">Log In</Link>\n        <Link to=\"/app\" className=\"btn-primary\">Get Started</Link>\n      </div>\n    </nav>\n  );\n};\n\nexport default Navbar;\n",
        "frontend/src/components/layout/Footer.tsx": "import React from 'react';\n\nconst Footer = () => {\n  return (\n    <footer className=\"border-t border-white/10 bg-surface/30 mt-20 py-12 px-8\">\n      <div className=\"max-w-6xl mx-auto flex flex-col md:flex-row justify-between items-center gap-6\">\n        <div className=\"text-gray-400 text-sm\">\n          &copy; {new Date().getFullYear()} TrustGuardAI. All rights reserved.\n        </div>\n        <div className=\"flex gap-6 text-sm text-gray-400\">\n          <a href=\"#\" className=\"hover:text-white transition\">Privacy Policy</a>\n          <a href=\"#\" className=\"hover:text-white transition\">Terms of Service</a>\n        </div>\n      </div>\n    </footer>\n  );\n};\n\nexport default Footer;\n",
        "frontend/src/pages/Landing.tsx": "import React from 'react';\nimport { Link } from 'react-router-dom';\nimport { motion } from 'framer-motion';\nimport { ShieldCheck, Zap, Lock, Globe, Cpu } from 'lucide-react';\n\nconst Landing = () => {\n  return (\n    <div className=\"flex flex-col items-center\">\n      {/* Hero Section */}\n      <section className=\"w-full max-w-6xl mx-auto px-6 py-32 flex flex-col items-center text-center\">\n        <motion.div\n          initial={{ opacity: 0, y: 20 }}\n          animate={{ opacity: 1, y: 0 }}\n          transition={{ duration: 0.7 }}\n        >\n          <div className=\"inline-flex items-center gap-2 px-3 py-1 rounded-full bg-primary/10 border border-primary/20 text-primary text-sm font-medium mb-8\">\n            <Zap size={14} /> \n            Google ADK Multi-Agent Architecture\n          </div>\n          <h1 className=\"text-5xl md:text-7xl font-extrabold tracking-tight mb-8 leading-tight\">\n            Protect Your Digital Life with <br />\n            <span className=\"bg-clip-text text-transparent bg-gradient-to-r from-primary via-accent to-primary animate-gradient-x\">\n              Explainable AI\n            </span>\n          </h1>\n          <p className=\"text-xl text-gray-400 max-w-2xl mx-auto mb-12\">\n            Detect fake websites and malicious QR codes before you log in or pay. TrustGuardAI uses a swarm of autonomous agents to interrogate threats in real-time.\n          </p>\n          <div className=\"flex flex-col sm:flex-row gap-4 justify-center\">\n            <Link to=\"/app\" className=\"btn-primary text-lg px-8 py-4\">\n              Launch Dashboard\n            </Link>\n            <Link to=\"/app/scan-website\" className=\"btn-secondary text-lg px-8 py-4\">\n              Scan a URL Now\n            </Link>\n          </div>\n        </motion.div>\n      </section>\n\n      {/* Features Section */}\n      <section id=\"features\" className=\"w-full max-w-6xl mx-auto px-6 py-20\">\n        <div className=\"grid grid-cols-1 md:grid-cols-3 gap-8\">\n          {[\n            { icon: Globe, title: \"Deep URL Analysis\", desc: \"WHOIS anomaly detection, SSL interrogation, and typosquatting prevention.\" },\n            { icon: Cpu, title: \"Antigravity Engine\", desc: \"DAG-based concurrent agent execution cuts scan times by 75%.\" },\n            { icon: Lock, title: \"MCP Threat Intel\", desc: \"Isolated execution of cybersecurity tools preventing direct LLM network access.\" }\n          ].map((feature, idx) => (\n            <motion.div \n              key={idx}\n              initial={{ opacity: 0, y: 20 }}\n              whileInView={{ opacity: 1, y: 0 }}\n              viewport={{ once: true }}\n              transition={{ delay: idx * 0.2 }}\n              className=\"glass-panel p-8\"\n            >\n              <div className=\"w-12 h-12 rounded-xl bg-primary/20 flex items-center justify-center mb-6\">\n                <feature.icon className=\"text-primary w-6 h-6\" />\n              </div>\n              <h3 className=\"text-xl font-bold mb-3\">{feature.title}</h3>\n              <p className=\"text-gray-400 leading-relaxed\">{feature.desc}</p>\n            </motion.div>\n          ))}\n        </div>\n      </section>\n\n      {/* Stats */}\n      <section className=\"w-full border-y border-white/10 bg-surface/50 py-20 mt-10\">\n        <div className=\"max-w-6xl mx-auto px-6 grid grid-cols-2 md:grid-cols-4 gap-8 text-center\">\n          {[ { v: \"99.9%\", l: \"Detection Rate\" }, { v: \"< 2s\", l: \"Scan Speed\" }, { v: \"5+\", l: \"Parallel Agents\" }, { v: \"0\", l: \"False Positives\" } ].map((stat, idx) => (\n            <div key={idx} className=\"space-y-2\">\n              <div className=\"text-4xl font-extrabold bg-clip-text text-transparent bg-gradient-to-br from-white to-gray-400\">\n                {stat.v}\n              </div>\n              <div className=\"text-sm text-gray-500 uppercase tracking-widest font-semibold\">{stat.l}</div>\n            </div>\n          ))}\n        </div>\n      </section>\n    </div>\n  );\n};\n\nexport default Landing;\n",
        "frontend/src/pages/Dashboard.tsx": "import React from 'react';\nimport { Link } from 'react-router-dom';\nimport { ShieldCheck, Globe, QrCode, AlertTriangle, ArrowRight, Lightbulb } from 'lucide-react';\nimport { motion } from 'framer-motion';\n\nconst Dashboard = () => {\n  return (\n    <div className=\"space-y-8\">\n      <header>\n        <h1 className=\"text-3xl font-bold mb-2\">Welcome back, Admin</h1>\n        <p className=\"text-gray-400\">Here is your security overview for today.</p>\n      </header>\n\n      {/* Stats Row */}\n      <div className=\"grid grid-cols-1 md:grid-cols-3 gap-6\">\n        {[ \n          { label: \"Total Scans\", val: \"1,284\", icon: ShieldCheck, color: \"text-primary\" },\n          { label: \"Threats Blocked\", val: \"342\", icon: AlertTriangle, color: \"text-warning\" },\n          { label: \"Average Risk Score\", val: \"12%\", icon: Globe, color: \"text-emerald-400\" } \n        ].map((stat, idx) => (\n          <motion.div \n            initial={{ opacity: 0, scale: 0.95 }}\n            animate={{ opacity: 1, scale: 1 }}\n            transition={{ delay: idx * 0.1 }}\n            key={idx} \n            className=\"glass-card p-6 flex items-center justify-between\"\n          >\n            <div>\n              <p className=\"text-sm text-gray-400 mb-1 font-medium\">{stat.label}</p>\n              <p className=\"text-3xl font-bold\">{stat.val}</p>\n            </div>\n            <div className={`p-4 rounded-full bg-white/5 ${stat.color}`}>\n              <stat.icon size={24} />\n            </div>\n          </motion.div>\n        ))}\n      </div>\n\n      <div className=\"grid grid-cols-1 lg:grid-cols-3 gap-8\">\n        {/* Main Actions */}\n        <div className=\"lg:col-span-2 space-y-6\">\n          <div className=\"glass-panel p-8 relative overflow-hidden\">\n            <div className=\"absolute top-0 right-0 p-12 opacity-10\">\n              <Globe size={120} />\n            </div>\n            <h2 className=\"text-xl font-bold mb-6\">Quick Scan</h2>\n            <div className=\"flex flex-col sm:flex-row gap-4\">\n              <Link to=\"/app/scan-website\" className=\"flex-1 glass-card p-6 flex flex-col items-center justify-center gap-4 group\">\n                <div className=\"w-16 h-16 rounded-full bg-primary/20 flex items-center justify-center group-hover:scale-110 transition-transform\">\n                  <Globe className=\"text-primary\" size={32} />\n                </div>\n                <span className=\"font-medium\">Scan URL</span>\n              </Link>\n              <Link to=\"/app/scan-qr\" className=\"flex-1 glass-card p-6 flex flex-col items-center justify-center gap-4 group\">\n                <div className=\"w-16 h-16 rounded-full bg-accent/20 flex items-center justify-center group-hover:scale-110 transition-transform\">\n                  <QrCode className=\"text-accent\" size={32} />\n                </div>\n                <span className=\"font-medium\">Scan QR Code</span>\n              </Link>\n            </div>\n          </div>\n\n          <div className=\"glass-panel p-8\">\n            <div className=\"flex items-center justify-between mb-6\">\n              <h2 className=\"text-xl font-bold\">Recent Scans</h2>\n              <Link to=\"/app/history\" className=\"text-sm text-primary hover:text-primary-dark flex items-center gap-1\">\n                View All <ArrowRight size={16} />\n              </Link>\n            </div>\n            <div className=\"space-y-4\">\n              {[ \n                { target: \"https://secure-login-paypal.com\", date: \"2 mins ago\", risk: 98, status: \"Malicious\" },\n                { target: \"https://github.com\", date: \"1 hour ago\", risk: 2, status: \"Safe\" },\n                { target: \"QR Code: Event Ticket\", date: \"3 hours ago\", risk: 15, status: \"Safe\" },\n              ].map((scan, i) => (\n                <div key={i} className=\"flex items-center justify-between p-4 bg-white/5 rounded-lg border border-white/5 hover:bg-white/10 transition-colors\">\n                  <div className=\"flex items-center gap-4\">\n                    <div className={`w-2 h-2 rounded-full ${scan.risk > 50 ? 'bg-danger animate-pulse' : 'bg-success'}`}></div>\n                    <div>\n                      <p className=\"font-medium truncate max-w-[200px] sm:max-w-xs\">{scan.target}</p>\n                      <p className=\"text-xs text-gray-500\">{scan.date}</p>\n                    </div>\n                  </div>\n                  <div className={`px-3 py-1 rounded-full text-xs font-semibold ${scan.risk > 50 ? 'bg-danger/20 text-danger border border-danger/30' : 'bg-success/20 text-success border border-success/30'}`}>\n                    {scan.status}\n                  </div>\n                </div>\n              ))}\n            </div>\n          </div>\n        </div>\n\n        {/* Sidebar Widgets */}\n        <div className=\"space-y-6\">\n          <div className=\"glass-panel p-6 bg-gradient-to-b from-surface to-primary/10 border-t-primary/50\">\n            <div className=\"flex items-center gap-3 mb-4\">\n              <div className=\"p-2 bg-warning/20 text-warning rounded-lg\">\n                <Lightbulb size={20} />\n              </div>\n              <h3 className=\"font-bold\">Cyber Tip</h3>\n            </div>\n            <p className=\"text-sm text-gray-300 leading-relaxed\">\n              Always check for typos in the domain name. Attackers often use characters that look similar (like replacing 'm' with 'rn') to trick you into entering credentials on a fake site.\n            </p>\n          </div>\n        </div>\n      </div>\n    </div>\n  );\n};\n\nexport default Dashboard;\n"
    }

    for path, content in files.items():
        os.makedirs(os.path.dirname(path), exist_ok=True)
        with open(path, "w", encoding="utf-8") as f:
            f.write(content)

if __name__ == "__main__":
    create_files()
    print("Frontend Phase 6 (Part 1) scaffolded.")
